    ("switchboard", "How do I use Switchboard oracles?",
     "```rust\nuse switchboard_solana::AggregatorAccountData;\n\npub fn read_price(ctx: Context<ReadPrice>) -> Result<()> {\n    let feed = &ctx.accounts.switchboard_feed;\n    let data = AggregatorAccountData::new(feed)?;\n    \n    let value = data.get_result()?;\n    let price = value.try_into_f64()?;\n    \n    // Check staleness\n    let staleness = Clock::get()?.unix_timestamp - data.latest_confirmed_round.round_open_timestamp;\n    require!(staleness < 60, OracleError::StaleFeed);\n    \n    msg!(\"Price: {}\", price);\n    Ok(())\n}\n```"),
    ("twap", "How do I calculate a TWAP (Time-Weighted Average Price)?",
     "```rust\n#[account]\npub struct TwapState {\n    pub cumulative_price: u128,\n    pub last_price: u64,\n    pub last_timestamp: i64,\n    pub observations: u32,\n}\n\npub fn update_twap(state: &mut TwapState, new_price: u64) -> Result<()> {\n    let clock = Clock::get()?;\n    let elapsed = (clock.unix_timestamp - state.last_timestamp) as u128;\n    \n    state.cumulative_price += state.last_price as u128 * elapsed;\n    state.last_price = new_price;\n    state.last_timestamp = clock.unix_timestamp;\n    state.observations += 1;\n    Ok(())\n}\n\npub fn get_twap(state: &TwapState, period_seconds: i64) -> u64 {\n    let clock = Clock::get().unwrap();\n    let elapsed = (clock.unix_timestamp - state.last_timestamp) as u128;\n    let current_cumulative = state.cumulative_price + state.last_price as u128 * elapsed;\n    (current_cumulative / period_seconds as u128) as u64\n}\n```"),
