PROCESSED.mkdir(parents=True, exist_ok=True)
out = PROCESSED / "synthetic-bulk11.jsonl"
with open(out, "w") as f:
    for r in records:
        f.write(json.dumps(r, ensure_ascii=False) + "\n")

print(f"Wrote {len(records)} records to {out}")
